```bash
sed -n '14230,14310p' llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp && sed -n '19460,19510p' llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp && sed -n '1,200p' llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp | grep -n "sext <4 x i1>" || sed -n '14000,14600p' llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp && sed -n '19350,19650p' llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp && applypatch << 'EOF'
*** Begin Patch
*** Update File: llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
@@
-    // For boolean vectors we currently sign-extend the lanes to the wider
-    // integer element type after freezing to avoid poison issues.
-    // However, sign-extension from i1 produces all-ones (-1) for true which
-    // is incorrect for unsigned comparisons and arithmetic operating on i8/i16
-    // that originated from zext of i1 scalars. Use zero-extension instead to
-    // preserve the original 0/1 semantics.
-    auto ExtendBoolLanes = [&](Value *V, Type *EltTy, IRBuilderBase &Builder) {
-      if (V->getType()->isVectorTy() &&
-          cast<VectorType>(V->getType())->getElementType()->isIntegerTy(1) &&
-          cast<VectorType>(V->getType())->getElementType()->isIntegerTy(1)) {
-        // Freeze the boolean vector before extension.
-        Value *Fr = Builder.CreateFreeze(V);
-        // Wrong: sign-extend i1 -> iN
-        // return Builder.CreateSExt(Fr, FixedVectorType::get(EltTy,
-        //                                       cast<VectorType>(V->getType())->getElementCount().getFixedValue()));
-        return Builder.CreateZExt(
-            Fr, FixedVectorType::get(
-                    EltTy,
-                    cast<VectorType>(V->getType())->getElementCount().getFixedValue()));
-      }
-      return V;
-    };
+    // For boolean vectors, extend lanes using zero-extension after freeze.
+    // Sign-extension from i1 produces -1 for true which breaks unsigned ops.
+    auto ExtendBoolLanes = [&](Value *V, Type *EltTy, IRBuilderBase &Builder) {
+      if (auto *VT = dyn_cast<VectorType>(V->getType())) {
+        if (VT->getElementType()->isIntegerTy(1)) {
+          // Freeze the boolean vector before extension to avoid poison.
+          Value *Fr = Builder.CreateFreeze(V);
+          return Builder.CreateZExt(
+              Fr, FixedVectorType::get(EltTy,
+                                       VT->getElementCount().getFixedValue()));
+        }
+      }
+      return V;
+    };
*** End Patch
EOF
